import { describe, expect, it } from 'vitest'

import { summarize } from './summarize.js'

const items = [
  { name: 'a', tags: ['priority'], score: 80 },
  { name: 'b', tags: ['p:high'], score: 60 },
  { name: 'c', tags: ['other'], score: 95 },
]

describe('summarize', () => {
  it('count mode reports the qualified count', () => {
    expect(summarize(items, 'count')).toBe('1 qualified')
  })
})

type Item = { name: string; tags: string[]; score: number }
type Mode = 'count' | 'ratio' | 'status'

export function summarize(items: Item[], mode: Mode): string {
  if (mode === 'count') {
    let qualified = 0
    for (const it of items) {
      let priority = false
      for (const tag of it.tags) {
        if (tag === 'priority' || tag.startsWith('p:')) {
          priority = true
          break
        }
      }
      if (priority && it.score >= 70) qualified += 1
    }
    return `${qualified} qualified`
  }
  return ''
}

