        if (tag === 'priority' || tag.startsWith('p:')) {
          priority = true
          break
        }
      }
      if (priority && it.score >= 70) qualified += 1
    }
    return `${qualified} qualified`
  }
  if (mode === 'ratio') {
    let qualified = 0
    for (const it of items) {
      let priority = false
      for (const tag of it.tags) {
        if (tag === 'priority' || tag.startsWith('p:')) {
          priority = true
          break
        }
      }
      if (priority && it.score >= 70) qualified += 1
    }
    return `${qualified}/${items.length}`
